// W2 — Build Input
// Edita los valores de `input` para probar distintos payloads.
//
// CONVENCIONES DEV:
//   - canal = "manual_dev"     -> prefijo de idempotency_key para pruebas DEV (no contamina canales reales)
//   - canal_origen = "manual"   -> queda registrado en pre_reservas.canal_origen
//   - source_event = "n8n_w02_crear_prereserva_manual" -> NO incluye el ambiente DEV
//
// CAMPOS HUÉSPED:
//   - huesped_nombre OBLIGATORIO
//   - al menos uno entre huesped_telefono / huesped_email OBLIGATORIO
//
// HORAS SOLICITADAS:
//   - Dejar como string vacío para que la función aplique los defaults v1.7.1.
//   - Llenar (formato "HH:MM:SS") para probar el caso hora_fuera_de_rango.

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (compone idempotency_key)
  canal: "manual_dev",
  id_evento: "test_w02_001",

  // Datos de la pre-reserva
  id_cabana: 17,
  fecha_in: "2026-07-10",
  fecha_out: "2026-07-13",
  personas: 2,
  monto_total: 150000,
  monto_sena: 50000,
  canal_origen: "manual",
  canal_pago_esperado: "transferencia_mp",

  // Huésped
  huesped_nombre: "Juan Pérez Test",
  huesped_telefono: "+5491134567890",
  huesped_email: "juan.test@example.com",

  // Opcionales
  notas: "",
  mascotas: false,
  detalle_mascotas: "",
  ninos: false,
  notas_reserva: "",

  // Horas solicitadas (vacío = usar defaults de la función)
  hora_checkin_solicitada: "",
  hora_checkout_solicitada: ""
};
// =============================================

return [{ json: input }];

// W2 — Build Payload
// Toma el input editable de Build Input y construye:
//   1. idempotency_key (convención 6C v1.2 Sección 5.4):
//        {canal}_{id_evento}_{id_cabana}_{fecha_in}_{fecha_out}
//   2. source_event (convención 6C v1.2 Sección 5.5):
//        n8n_w02_crear_prereserva_manual
//   3. payload JSONB completo según contrato de crear_prereserva(jsonb).
//
// CONTRATO PAYLOAD: ver firma real de crear_prereserva en 6B_SCHEMA_SQL.md
// v1.7.1 Sección 13 (Bloque 11).
//
// Campos opcionales vacíos -> null (la función los procesa con NULLIF).

const input = $input.first().json;

const idempotency_key =
  `${input.canal}_${input.id_evento}_${input.id_cabana}_${input.fecha_in}_${input.fecha_out}`;

const source_event = 'n8n_w02_crear_prereserva_manual';

// Helper: convierte string vacío en null, deja el resto tal cual
const nv = (v) => (v === '' || v === undefined ? null : v);

const payload = {
  id_cabana: input.id_cabana,
  fecha_in: input.fecha_in,
  fecha_out: input.fecha_out,
  personas: input.personas,
  monto_total: input.monto_total,
  monto_sena: input.monto_sena,
  canal_origen: input.canal_origen,
  canal_pago_esperado: input.canal_pago_esperado,
  source_event,
  idempotency_key,
  notas: nv(input.notas),
  mascotas: input.mascotas,
  detalle_mascotas: nv(input.detalle_mascotas),
  ninos: input.ninos,
  notas_reserva: nv(input.notas_reserva),
  hora_checkin_solicitada: nv(input.hora_checkin_solicitada),
  hora_checkout_solicitada: nv(input.hora_checkout_solicitada),
  huesped: {
    nombre: input.huesped_nombre,
    telefono: nv(input.huesped_telefono),
    email: nv(input.huesped_email)
  }
};

return [{
  json: {
    payload,
    idempotency_key,
    source_event,
    input  // se preserva para trazabilidad en Build Response
  }
}];

// W2 — Build Response
// Interpreta el JSONB que devuelve crear_prereserva() y arma el wrapper estándar
// según 6C v1.2 Sección 5.6.
//
// Contrato de salida de la función:
//   - happy:        { ok: true, idempotent_match: false, id_pre_reserva, id_huesped,
//                     estado, expira_en, hora_checkin, hora_checkout, recovery_path: null }
//   - idempotente:  { ok: true, idempotent_match: true, id_pre_reserva, id_huesped,
//                     estado, expira_en, recovery_path: "pre_lock"|"post_lock"|"unique_violation" }
//   - error:        { ok: false, error: "<codigo>", ...detalle según error }
//
// CONVENCIÓN DEL WRAPPER:
//   - ok = true cuando la pre-reserva existe AHORA (creada o ya existente por idempotencia).
//   - ok = false con error_code cuando no se pudo crear.
//   - Se preservan idempotency_key y source_event para trazabilidad.
//   - result siempre lleva el JSONB completo de la función, sin reinterpretar.
//
// FILTER DEFENSIVO: si el Postgres node tiene Always Output Data y la función
// no devolvió fila (caso muy improbable), items[0].json no tendrá .resultado.

const buildPayload = $('Build Payload').first().json;
const pgItem = items[0]?.json;
const resultado = pgItem?.resultado;

if (!resultado || typeof resultado !== 'object') {
  return [{
    json: {
      ok: false,
      workflow: 'vita_w02_crear_prereserva_supabase',
      source_event: buildPayload.source_event,
      idempotency_key: buildPayload.idempotency_key,
      error: 'sin_respuesta_de_funcion',
      result: null,
      executed_at: new Date().toISOString()
    }
  }];
}

const ok = resultado.ok === true;

return [{
  json: {
    ok,
    workflow: 'vita_w02_crear_prereserva_supabase',
    source_event: buildPayload.source_event,
    idempotency_key: buildPayload.idempotency_key,
    error: ok ? null : (resultado.error || 'error_desconocido'),
    result: resultado,
    executed_at: new Date().toISOString()
  }
}];
